$invoicesId = entity\attribute('invoicesId');

output\printLine(string\concatenate('Invoice Id: ', $invoicesId));

if (!$invoicesId) {
    return;
}

/*
 Fetch all Invoice records related to Project
*/
$invoicePaymentList = record\findMany(
    'CInvoicePayment',
    200,
    'createdAt',
    'asc',
    'invoicesId',
    $invoicesId
);
output\printLine($invoicePaymentList);
$totalAmount = 0;

/*
 Loop through invoices
*/
$i = 0;

while ($i < array\length($invoicePaymentList)) {
    output\printLine(string\concatenate('$i =  ', $i));
    
    $amount = record\attribute('CInvoicePayment',$invoicePaymentList[$i] , 'amount');
    output\print(string\concatenate('amount: ', $amount));

    if ($amount) {
        $totalAmount = $totalAmount + $amount;
    }

    $i = $i + 1;
}
output\printLine(string\concatenate('Total invoice Amount: ', $totalAmount));


/*
 Update Project field
*/
$projectId = record\attribute('CInvoices',$invoicesId , 'projectId');

$amountInr = record\attribute('CInvoices', $invoicesId, 'amountInr');

$dueAmount = $amountInr - $totalAmount;
record\update(
    'CInvoices',
    $invoicesId,
    'dueAmount',
    $dueAmount
);
record\update(
    'Project',
    $projectId,
    'totalPaymentRecieved',
    $totalAmount
);
